import React from 'react';
import { Link } from 'react-router-dom';
import { AppBar, Toolbar, Button, Typography, Box } from '@mui/material';

const Navbar = () => {
  return (
    <AppBar position="static" color="default" elevation={0}>
      <Toolbar>
        <Box display="flex" flexGrow={1} alignItems="center">
          <Typography variant="h6" color="inherit" noWrap>
            <Link to="/" style={{ textDecoration: 'none', color: 'inherit', marginRight: '15px' }}>
              Home
            </Link>
          </Typography>
          <Link to="/dataset" style={{ textDecoration: 'none', color: 'inherit', marginRight: '15px' }}>
            Dataset
          </Link>
          <Link to="/bgp_llama" style={{ textDecoration: 'none', color: 'inherit', marginRight: '15px' }}>
            BGP-LLaMA
          </Link>
        </Box>
        <Button color="primary" variant="contained" component={Link} to="https://huggingface.co/hyonbokan/BGPStream13-10k-cutoff-1024-max-2048">
          Download models
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
